const today = new Date().toISOString().split('T')[0];

// ─────────────────────────────────────────────────────────────────────────────
// Drop-in replacement for the "Mock Signals" Code node in your n8n workflow.
// Paste the entire contents below into the node body, replacing the existing code.
//
// 20 signals designed to exercise every stage of the pipeline:
//   • Theme 1 (signals 1–4):   Checkout crash regression cluster on v5.2
//                              → tests regression detection AND dedup (#4 ≈ #1)
//   • Theme 2 (signals 5–7):   Search filter reset
//   • Theme 3 (signals 8–10):  Returns / refund opacity
//   • Theme 4 (signals 11–13): Delivery tracking stale
//   • Theme 5 (signals 14–16): Prime double-charge
//   • Signal 17–18:            NOISE — vague/positive, should be marked
//                              irrelevant by Agent 2 (Signal Cleaner)
//   • Signal 19:               Product detail (misleading images) — singleton
//   • Signal 20:               Account login broken on v5.2 — extends the
//                              regression cluster into account_performance,
//                              so the regression spans 2 feature groups
//
// Sources mix:  app_store ×10  •  play_store ×4  •  amazon_review ×6
// Severity range when scored: ~1.0 (noise) to ~4.8 (checkout crash)
// All 7 feature groups represented in expected tagging output.
// ─────────────────────────────────────────────────────────────────────────────

const mockSignals = [
  // ─── Theme 1: Checkout crash after v5.2 update (regression cluster) ───
  {
    text: "After the 5.2 update the app keeps crashing the second I hit place order. Lost my cart 3 times this week. Had to use the browser instead. fix this please.",
