    app_version: "5.2"
  },
];

return mockSignals.map(s => ({ json: s }));

// Get all items — handle both direct and wrapped formats
const items = $input.all();

// Calculate week ID
const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNum = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const weekId = `${now.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;

const validSources = ['app_store', 'play_store', 'amazon_review'];

const normalized = [];
for (const item of items) {
  const d = item.json;
  const text = (d.text || '').trim();
  if (text.length < 10) continue;

  const source = validSources.includes(d.source) ? d.source : 'unknown';

  let date = d.date || new Date().toISOString().split('T')[0];
  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) {
    date = new Date().toISOString().split('T')[0];
  }

  const rating = (d.rating !== null && d.rating !== undefined && !isNaN(d.rating))
    ? Math.min(5, Math.max(1, Number(d.rating)))
    : null;

  normalized.push({
    text,
    source,
    date,
    rating,
    severity_raw: null,
    app_version: d.app_version || null
  });
}

// Build source breakdown
const breakdown = { app_store: 0, play_store: 0, amazon_review: 0, unknown: 0, total: 0 };
for (const s of normalized) {
  breakdown[s.source] = (breakdown[s.source] || 0) + 1;
  breakdown.total++;
}

// Data quality warning
let dataQualityWarning = null;
if (breakdown.total < 40) {
  dataQualityWarning = `Low signal volume: only ${breakdown.total} signals collected (minimum 40 expected).`;
}
if (breakdown.amazon_review === 0) {
  dataQualityWarning = (dataQualityWarning ? dataQualityWarning + ' ' : '') + 'Amazon reviews unavailable.';
}
if (breakdown.app_store === 0) {
  dataQualityWarning = (dataQualityWarning ? dataQualityWarning + ' ' : '') + 'App Store reviews unavailable.';
}

const _meta = {
  sourceBreakdown: breakdown,
  dataQualityWarning,
  weekId
};

// _meta on ALL items (not just first) so it's never lost downstream
return normalized.map(s => ({
  json: { ...s, _meta }
}));

const items = $input.all();

let _meta = null;
const signals = items.map((item, i) => {
  if (item.json._meta) _meta = item.json._meta;
  return {
    id: i,
    text: item.json.text,
    source: item.json.source,
    date: item.json.date,
    rating: item.json.rating,
    app_version: item.json.app_version
  };
});

const prompt = `You are a product discovery analyst. Analyse the following customer signals and return a JSON array.For EACH signal, return:
- id: (same id as input)
- duplicate: true if this signal is nearly identical in meaning to another signal, false otherwise
- irrelevant: true if the signal is vague, spam, non-English, or provides no actionable product insight, false otherwise
- severity_score: a float from 1.0 to 5.0 where 5.0 = critical product-breaking issue, 3.0 = moderate friction, 1.0 = minor or positive feedback
- version_flagged: true if the signal mentions a specific version number (e.g. "5.2", "v5") or phrases like "after the update" / "since the update", false otherwise

RULES:
- severity_score must always be a float between 1.0 and 5.0. Never null, never outside this range.
- Only mark duplicate: true on the LATER of two similar signals (keep the first)
- irrelevant signals still need a severity_score
- Return ONLY a valid JSON array. No markdown, no backticks, no explanation.
- Please make sure the JSON is valid so there are no invalid JSON errors in n8n

FEW-SHOT EXAMPLES:
Input: "App crashes on checkout after update to 5.0, lost my order" -> severity_score: 4.5, version_flagged: true, duplicate: false, irrelevant: false
Input: "ok" -> severity_score: 1.0, irrelevant: true, duplicate: false, version_flagged: false
Input: "Delivery was late by 3 days, no updates from courier" -> severity_score: 3.0, version_flagged: false, duplicate: false, irrelevant: false
Input: "App crashes on checkout, same issue as before" -> severity_score: 4.5, duplicate: true, irrelevant: false, version_flagged: false

SIGNALS TO ANALYSE:
${JSON.stringify(signals, null, 2)}`;

return [{ json: { prompt, signals, _meta } }];

const geminiResponse = $input.first().json;
const prevNode = $('Prepare Gemini Prompt').first().json;
const originalSignals = prevNode.signals;
const _meta = prevNode._meta;

const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
const cleaned = rawText.replace(/```json|```/g, '').trim();

let geminiResults;
try {
  geminiResults = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Gemini returned invalid JSON: ${cleaned.substring(0, 200)}`);
}

const validatedSignals = [];
for (const result of geminiResults) {
  if (result.duplicate === true) continue;
  if (result.irrelevant === true) continue;

  const original = originalSignals[result.id];
  if (!original) continue;

  const score = parseFloat(result.severity_score);
  if (isNaN(score) || score < 1.0 || score > 5.0) {
    throw new Error(`Invalid severity_score for signal ${result.id}: ${result.severity_score}`);
  }

  validatedSignals.push({
    text: original.text,
    source: original.source,
    date: original.date,
    rating: original.rating,
    app_version: original.app_version,
    severity_score: Math.round(score * 10) / 10,
    version_flagged: result.version_flagged === true,
    _meta
  });
}

if (validatedSignals.length === 0) {
  throw new Error('Zero signals survived cleaning. Check Gemini response.');
}

return validatedSignals.map(s => ({ json: s }));

const items = $input.all();
const REGRESSION_THRESHOLD = 5; // SET TO 1 FOR TESTING

let _meta = null;
const signals = items.map(item => {
  if (item.json._meta) _meta = item.json._meta;
  return item.json;
});

const versionGroups = {};
for (const signal of signals) {
  if (!signal.version_flagged) continue;
  const match = signal.text.match(/\b(\d+\.\d+[\.\d]*)\b/);
  const version = match ? match[1] : 'unknown';
  if (!versionGroups[version]) versionGroups[version] = [];
  versionGroups[version].push(signal);
}

const regressions = [];
for (const [version, vSignals] of Object.entries(versionGroups)) {
  if (vSignals.length >= REGRESSION_THRESHOLD) {
    regressions.push({
      version,
      signal_count: vSignals.length,
      top_signals: vSignals.slice(0, 3).map(s => s.text),
      feature_groups_affected: []
    });
  }
}

const updatedMeta = { ..._meta, regressions };

return signals.map(s => ({
  json: { ...s, _meta: updatedMeta }
}));

