const items = $input.all();

// Carry signals and _meta forward
let _meta = null;
const signals = items.map(item => {
  if (item.json._meta) _meta = item.json._meta;
  return item.json;
});

const config = {
  feature_groups: [
    { id: "search_discovery", name: "Search & Discovery", keywords: ["search", "filter", "results", "autocomplete", "browse", "sort", "query", "find"] },
    { id: "checkout_payment", name: "Checkout & Payment", keywords: ["checkout", "payment", "cart", "buy", "purchase", "order", "credit card", "billing", "crash"] },
    { id: "delivery_tracking", name: "Delivery & Tracking", keywords: ["delivery", "shipping", "tracking", "late", "package", "courier", "dispatch", "arrived"] },
    { id: "returns_refunds", name: "Returns & Refunds", keywords: ["return", "refund", "money back", "replace", "exchange", "sent back", "pending"] },
    { id: "product_detail", name: "Product Detail Pages", keywords: ["image", "photo", "description", "listing", "wrong item", "misleading", "specs", "review"] },
    { id: "prime_subscriptions", name: "Prime & Subscriptions", keywords: ["prime", "subscription", "charged", "membership", "renew", "cancel", "benefit", "double charge"] },
    { id: "account_performance", name: "Account & Performance", keywords: ["login", "password", "account", "slow", "crash", "freeze", "loading", "performance", "update", "bug"] }
  ],
  valid_ids: ["search_discovery", "checkout_payment", "delivery_tracking", "returns_refunds", "product_detail", "prime_subscriptions", "account_performance"]
};

return signals.map(s => ({
  json: { ...s, _config: config, _meta }
}));

const items = $input.all();

let _meta = null;
let _config = null;
const signals = items.map((item, i) => {
  if (item.json._meta) _meta = item.json._meta;
  if (item.json._config) _config = item.json._config;
  return {
  id: i,
  text: item.json.text,
  source: item.json.source,
  date: item.json.date,
  rating: item.json.rating,
  severity_score: item.json.severity_score,
  version_flagged: item.json.version_flagged,
  app_version: item.json.app_version || null
};
});

const validIds = _config.valid_ids.join(', ');

const prompt = `You are a product discovery analyst for the Amazon Shopping App.

You will perform TWO tasks on the signals below.

---
TASK 1 — THEME CLUSTERING:
Group the signals into 3–6 specific pain themes.
Theme labels must be specific and actionable:
✓ GOOD: "Search price filter resets after scrolling"
✗ BAD: "Search issues"

For each theme return:
- theme_id: t1, t2, t3... (sequential)
- theme_label: specific descriptive label
- trend_direction: "worsening" | "stable" | "improving"
- signal_ids: array of signal ids belonging to this theme

---
TASK 2 — FEATURE GROUP TAGGING:
For every signal, assign exactly one feature_group_id from this list:
${validIds}

RULES:
- ONLY use IDs from the exact list above. Never invent new ones.
- If a signal doesn't fit any group, use "account_performance" as fallback
- One signal = one feature_group_id, no exceptions

FEW-SHOT EXAMPLES:
"App crashes at checkout" → checkout_payment
"Search filters reset when scrolling" → search_discovery
"Prime membership charged twice" → prime_subscriptions
"Package hasn't arrived, tracking not updating" → delivery_tracking
"Product images don't match item received" → product_detail
"Can't log in after update" → account_performance

---
Return ONLY a valid JSON object with this exact structure. No markdown, no backticks:
{
  "themes": [
    {
      "theme_id": "t1",
      "theme_label": "string",
      "trend_direction": "worsening|stable|improving",
      "signal_ids": [0, 1, 2]
    }
  ],
  "signal_tags": [
    {
      "id": 0,
      "feature_group_id": "string",
      "theme_id": "string"
    }
  ]
}

SIGNALS:
${JSON.stringify(signals, null, 2)}`;

return [{ json: { prompt, signals, _meta, _config } }];

const geminiResponse = $input.first().json;
const prevNode = $('Prepare Synthesis Prompt').first().json;
const originalSignals = prevNode.signals;
const _meta = prevNode._meta;
const _config = prevNode._config;

const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
const cleaned = rawText.replace(/```json|```/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Gemini synthesis returned invalid JSON: ${cleaned.substring(0, 200)}`);
}

const { themes, signal_tags } = parsed;

const validIds = _config.valid_ids;
for (const tag of signal_tags) {
  if (!validIds.includes(tag.feature_group_id)) {
    throw new Error(`Invalid feature_group_id "${tag.feature_group_id}" for signal ${tag.id}. Valid IDs: ${validIds.join(', ')}`);
  }
}

const tagLookup = {};
for (const tag of signal_tags) {
  tagLookup[tag.id] = tag;
}

const themeLookup = {};
for (const theme of themes) {
  themeLookup[theme.theme_id] = theme;
}

const taggedSignals = originalSignals.map((signal, i) => {
  const tag = tagLookup[i] || {};
  const theme = themeLookup[tag.theme_id] || {};
  return {
    ...signal,
    feature_group_id: tag.feature_group_id || 'account_performance',
    theme_id: tag.theme_id || 'unclassified',
    theme_label: theme.theme_label || 'Unclassified',
    trend_direction: theme.trend_direction || 'stable',
    _meta,
    _config
  };
});

return taggedSignals.map(s => ({ json: s }));

const items = $input.all();
const now = new Date().toISOString();

return items.map((item, i) => {
  const s = item.json;
  return {
    json: {
      ID: `${s._meta.weekId}-${i}`,
      Text: s.text,
      Source: s.source,
      Date: s.date,
      Rating: s.rating,
      'Severity Score': s.severity_score,
      'Feature Group ID': s.feature_group_id,
      'Theme ID': s.theme_id,
      'Theme Label': s.theme_label,
      'Week ID': s._meta.weekId,
      'App Version': s.app_version || '',
      'Version Flagged': s.version_flagged ? 'TRUE' : 'FALSE',
      'Created At': now
    }
  };
});

const allItems = $input.all();
const lastWeekData = allItems[0]?.json?.empty 
  ? [] 
  : allItems.map(item => item.json);

const signalItems = $('Parse + Validate - Synthesis').all();
const signals = signalItems.map(item => item.json);
const _meta = signals[0]?._meta;
const _config = signals[0]?._config;

const byGroup = {};
for (const signal of signals) {
  const gid = signal.feature_group_id || 'account_performance';
  if (!byGroup[gid]) byGroup[gid] = [];
  byGroup[gid].push(signal);
}

const themesByGroup = {};
for (const signal of signals) {
  const gid = signal.feature_group_id || 'account_performance';
  if (!themesByGroup[gid]) themesByGroup[gid] = {};
  const tid = signal.theme_id || 'unclassified';
  if (!themesByGroup[gid][tid]) {
    themesByGroup[gid][tid] = {
      theme_id: tid,
      theme_label: signal.theme_label || 'Unclassified',
      trend_direction: signal.trend_direction || 'stable',
      signals: []
    };
  }
  themesByGroup[gid][tid].signals.push(signal);
}

const themesPerGroup = {};
for (const [gid, themes] of Object.entries(themesByGroup)) {
  themesPerGroup[gid] = Object.values(themes);
}

return [{
  json: {
    byGroup,
    themesPerGroup,
    allSignals: signals,
    lastWeekData,
    weekId: _meta?.weekId,
    _meta,
    _config
  }
}];

// ─── INPUT ────────────────────────────────────────────────────────────────────
const input = $input.first().json;
const { byGroup, themesPerGroup, allSignals, lastWeekData, weekId, _meta, _config } = input;

const regressions = _meta.regressions || [];

// ─── HELPERS ──────────────────────────────────────────────────────────────────

const SOURCE_CONFIDENCE = { 1: 0.6, 2: 0.8, 3: 1.0 };
const TREND_MULTIPLIER  = { worsening: 1.2, stable: 1.0, improving: 0.8 };

function getVersionRatioMultiplier(signals) {
  const flagged = signals.filter(s => s.version_flagged).length;
  const ratio = signals.length > 0 ? flagged / signals.length : 0;
  return 1 + (ratio * 0.2); // up to +20% boost
}

function getEffort(groupId) {
  const isRegression = regressions.some(r =>
    Array.isArray(r.feature_groups_affected) &&
    r.feature_groups_affected.includes(groupId)
  );
  return isRegression ? 0.8 : 1;
}

function scoreTheme(theme, groupId) {
  const signals = theme.signals || [];
  if (signals.length === 0) return 0;
  const reach             = signals.length;
  const avgSeverity       = signals.reduce((sum, s) => sum + (s.severity_score || 3.0), 0) / signals.length;
  const sources           = new Set(signals.map(s => s.source)).size;
  const confidence        = SOURCE_CONFIDENCE[Math.min(sources, 3)] || 0.6;
  const versionMultiplier = getVersionRatioMultiplier(signals);
  const trendMultiplier   = TREND_MULTIPLIER[theme.trend_direction] || 1.0;
  const effort            = getEffort(groupId);
  return ((reach * avgSeverity * confidence * versionMultiplier) / effort) * trendMultiplier;
}

// ─── DEDUPLICATE LAST WEEK DATA ───────────────────────────────────────────────
const seenRows = new Set();
const dedupedLastWeek = (lastWeekData || []).filter(r => {
  const key = `${r['Week ID']}_${r['Feature Group ID']}_${r.row_number}`;
  if (seenRows.has(key)) return false;
  seenRows.add(key);
  return true;
});

// Build a lookup: groupId → last week's best row (highest RICE score row)
const lastWeekLookup = {};
for (const row of dedupedLastWeek) {
  const gid = row['Feature Group ID'];
  if (!gid) continue;
  const existing = lastWeekLookup[gid];
  const rowRice  = parseFloat(row['Top RICE Score']) || 0;
  if (!existing || rowRice > (parseFloat(existing['Top RICE Score']) || 0)) {
    lastWeekLookup[gid] = row;
  }
}

// ─── SCORE EACH GROUP ─────────────────────────────────────────────────────────

const scoredGroups = [];

for (const [groupId, signals] of Object.entries(byGroup)) {
  if (!signals || signals.length === 0) continue;

  const themes = themesPerGroup[groupId] || [];

  // Score each theme individually
  const scoredThemes = themes.map(t => ({
    theme_id:        t.theme_id,
    theme_label:     t.theme_label,
    trend_direction: t.trend_direction,
    signal_count:    (t.signals || []).length,
    theme_score:     Math.round(scoreTheme(t, groupId) * 10) / 10
  }));

  // Group RICE = top theme score
  const topTheme = scoredThemes.reduce(
    (best, t) => t.theme_score > best.theme_score ? t : best,
    scoredThemes[0] || { theme_score: 0 }
  );
  const topRiceScore = topTheme.theme_score || 0;

  // Group-level metrics (for display + WoW)
  const reach       = signals.length;
  const avgSeverity = Math.round(
    (signals.reduce((sum, s) => sum + (s.severity_score || 3.0), 0) / signals.length) * 10
  ) / 10;
  const sources           = new Set(signals.map(s => s.source)).size;
  const confidence        = SOURCE_CONFIDENCE[Math.min(sources, 3)] || 0.6;
  const versionMultiplier = getVersionRatioMultiplier(signals);

  const hasWorsening  = themes.some(t => t.trend_direction === 'worsening');
  const allImproving  = themes.length > 0 && themes.every(t => t.trend_direction === 'improving');
  const trendKey      = hasWorsening ? 'worsening' : allImproving ? 'improving' : 'stable';
  const trendMultiplier = TREND_MULTIPLIER[trendKey];
  const effort          = getEffort(groupId);

  scoredGroups.push({
    feature_group_id:  groupId,
    top_rice_score:    topRiceScore,
    avg_severity:      avgSeverity,
    signal_count:      reach,
    confidence,
    version_multiplier: Math.round(versionMultiplier * 100) / 100,
    effort,
    trend_direction:   trendKey,
    trend_multiplier:  trendMultiplier,
    top_theme:         topTheme.theme_label || '',
    scored_themes:     scoredThemes
  });
}

// ─── SORT BY RICE SCORE ───────────────────────────────────────────────────────
scoredGroups.sort((a, b) => b.top_rice_score - a.top_rice_score);

// ─── DYNAMIC MoSCoW (PERCENTILE-BASED) ───────────────────────────────────────
const sortedScores = scoredGroups.map(g => g.top_rice_score).sort((a, b) => a - b);

function percentile(arr, p) {
  if (arr.length === 0) return 0;
  const idx = Math.ceil((p / 100) * arr.length) - 1;
  return arr[Math.max(0, idx)];
}

const p75 = percentile(sortedScores, 75);
const p50 = percentile(sortedScores, 50);
const p25 = percentile(sortedScores, 25);

function getMoSCoW(score) {
  if (score >= p75) return 'Must Have';
  if (score >= p50) return 'Should Have';
  if (score >= p25) return 'Could Have';
  return "Won't Have";
}

// Attach MoSCoW to each group
scoredGroups.forEach(g => {
  g.top_moscow = getMoSCoW(g.top_rice_score);
});

// Overall top group (for digest header)
const overallTop = scoredGroups[0] || null;
console.log(`Agent 4 Node 1: Top group = ${overallTop?.feature_group_id} (RICE ${overallTop?.top_rice_score}, ${overallTop?.top_moscow})`);

