scoredGroups.forEach(g => dist[g.top_moscow]++);
console.log('MoSCoW distribution:', JSON.stringify(dist));

// ─── OUTPUT ───────────────────────────────────────────────────────────────────
// Pass scoredGroups + lastWeekLookup forward to Node 2 (WoW Delta)
// All original fields are preserved for Agent 5
return [{
  json: {
    scoredGroups,
    lastWeekLookup,
    byGroup,
    themesPerGroup,
    allSignals,
    lastWeekData,
    weekId,
    _meta,
    _config
  }
}];

// ─── INPUT ────────────────────────────────────────────────────────────────────
// Receives scoredGroups + lastWeekLookup from Node 1
